INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'lv', 21, 1, NULL, 'Joseph Benson em Lv 21:1', 'Joseph Benson destaca a exposição textual com aplicação pastoral objetiva. Em Levítico 21, o foco recai sobre aliança, santidade e obediência e chama a igreja para justiça com misericórdia. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Joseph Benson', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'lv', 22, 1, NULL, 'Martin Bucer em Lv 22:1', 'Na leitura de Martin Bucer, vemos a centralidade das Escrituras e da graça soberana. Levítico 22 evidencia aliança, santidade e obediência como eixo da vida do povo de Deus, com ênfase em adoração reverente. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Martin Bucer', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'lv', 23, 1, NULL, 'Charles Finney em Lv 23:1', 'Segundo Charles Finney, o chamado ao arrependimento, fé viva e missão ilumina o sentido deste texto. Levítico 23 mostra que aliança, santidade e obediência sustenta a caminhada da fé, especialmente em amor fraternal. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Charles Finney', 'commentary', '#0E7490', NOW()),
(gen_random_uuid(), 'lv', 24, 1, NULL, 'Jamieson-Fausset-Brown em Lv 24:1', 'Na leitura de Jamieson-Fausset-Brown, vemos a exposição textual com aplicação pastoral objetiva. Levítico 24 evidencia aliança, santidade e obediência como eixo da vida do povo de Deus, com ênfase em arrependimento sincero. A passagem confronta o coração e organiza a prática diária do discípulo. Aplicação: submeta sua vontade à Palavra e caminhe em fidelidade.', 'Jamieson-Fausset-Brown', 'commentary', '#B45309', NOW()),
(gen_random_uuid(), 'lv', 25, 1, NULL, 'John Knox em Lv 25:1', 'John Knox interpreta este versículo a partir de a centralidade das Escrituras e da graça soberana. Em Levítico 25, Deus revela aliança, santidade e obediência de forma pastoral e transformadora, promovendo vida de oração. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'John Knox', 'commentary', '#800080', NOW()),
(gen_random_uuid(), 'lv', 26, 1, NULL, 'George Whitefield em Lv 26:1', 'George Whitefield destaca o chamado ao arrependimento, fé viva e missão. Em Levítico 26, o foco recai sobre aliança, santidade e obediência e chama a igreja para santidade prática. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'George Whitefield', 'commentary', '#0E7490', NOW()),
